 92	  const resetActiveAndFocusedItem = () => {
 93	    setFocusedItemIndex(null);
 94	    setActiveItemId(null);
 95	  };
 96	
 97	  const closeMenu = () => {
 98	    setIsOpen(false);
 99	    resetActiveAndFocusedItem();
100	  };
101	
102	  const onInputClick = () => {
103	    if (!isOpen) {
104	      setIsOpen(true);
105	    } else if (!inputValue) {
106	      closeMenu();
107	    }
108	  };
109	
110	  const selectOption = (value: string | number) => {
111	    if (value && value !== NO_RESULTS) {
112	      const optionText = selectOptions.find(
113	        (option) => option.value === value
114	      )?.children;
115	      setInputValue(String(optionText));
116	      setFilterValue('');
117	      setSelected(String(value));
118	
119	      closeMenu();
120	    }
121	  };
122	
123	  const onOptionSelect = (
124	    _event: React.SyntheticEvent | undefined,
125	    value: SelectOptionProps['value'] | undefined
126	  ) => {
127	    const optionValue = String(value || '');
128	    selectOption(optionValue);
129	    onSelect(optionValue);
130	    setIsUserSelection(true);
131	  };
132	
133	  // We update the preselected value on re-render if the user hasn't interacted yet.
134	  if (!isUserSelection && selectedValueText !== selected) {
135	    selectOption(selectedValueText);
136	  }
137	
138	  const onTextInputChange = (
139	    _event: React.FormEvent<HTMLInputElement>,
140	    value: string
141	  ) => {
142	    setInputValue(value);
143	    setFilterValue(value);
144	
145	    resetActiveAndFocusedItem();
146	
147	    if (value !== selected) {
148	      setSelected('');
149	      setIsUserSelection(true);
150	    }
151	  };
152	
153	  const handleMenuArrowKeys = (key: string) => {
154	    let indexToFocus = 0;
155	
156	    if (!isOpen) {
157	      setIsOpen(true);
158	    }
159	
160	    if (selectOptions.every((option) => option.isDisabled)) {
161	      return;
162	    }
163	
164	    if (key === 'ArrowUp') {
165	      // When no index is set or at the first index, focus to the last, otherwise decrement focus index
166	      if (focusedItemIndex === null || focusedItemIndex === 0) {
167	        indexToFocus = selectOptions.length - 1;
168	      } else {
169	        indexToFocus = focusedItemIndex - 1;
170	      }
171	
172	      // Skip disabled options
173	      while (selectOptions[indexToFocus].isDisabled) {
174	        indexToFocus--;
175	        if (indexToFocus === -1) {
176	          indexToFocus = selectOptions.length - 1;
177	        }
178	      }
179	    }
180	
181	    if (key === 'ArrowDown') {
182	      // When no index is set or at the last index, focus to the first, otherwise increment focus index
183	      if (
184	        focusedItemIndex === null ||
185	        focusedItemIndex === selectOptions.length - 1
186	      ) {
187	        indexToFocus = 0;
188	      } else {
189	        indexToFocus = focusedItemIndex + 1;
190	      }
191	
192	      // Skip disabled options
193	      while (selectOptions[indexToFocus].isDisabled) {
194	        indexToFocus++;
195	        if (indexToFocus === selectOptions.length) {
196	          indexToFocus = 0;
197	        }
198	      }
199	    }
200	
201	    setActiveAndFocusedItem(indexToFocus);
202	  };
203	
204	  const onInputKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
205	    const focusedItem =
206	      focusedItemIndex !== null ? selectOptions[focusedItemIndex] : null;
207	
208	    switch (event.key) {
209	      case 'Enter':
210	        if (isOpen && focusedItem && !focusedItem?.isAriaDisabled) {
211	          onOptionSelect(event, focusedItem?.value);
212	        }
213	
214	        if (!isOpen) {
215	          setIsOpen(true);
216	        }
217	
218	        break;
219	      case 'ArrowUp':
220	      case 'ArrowDown':
221	        event.preventDefault();
222	        handleMenuArrowKeys(event.key);
223	        break;
224	    }
225	  };
226	
227	  const onToggleClick = () => {
228	    setIsOpen(!isOpen);
229	    textInputRef?.current?.focus();
230	  };
231	
232	  const onClearButtonClick = () => {
233	    setSelected('');
234	    setInputValue('');
235	    setFilterValue('');
236	    resetActiveAndFocusedItem();
237	    textInputRef?.current?.focus();
238	    onSelect('');
239	    setIsUserSelection(true);
240	  };
241	
242	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
243	    <MenuToggle
244	      ref={toggleRef}
245	      variant="typeahead"
246	      aria-label={ariaLabel}
247	      onClick={onToggleClick}
248	      isExpanded={isOpen}
249	      isFullWidth
250	    >
251	      <TextInputGroup isPlain>
252	        <TextInputGroupMain
253	          value={inputValue}
254	          onClick={onInputClick}
255	          onChange={onTextInputChange}
256	          onKeyDown={onInputKeyDown}
257	          id={`${id}-input`}
258	          autoComplete="off"
259	          innerRef={textInputRef}
260	          placeholder={placeholder}
261	          {...(activeItemId && { 'aria-activedescendant': activeItemId })}
262	          role="combobox"
263	          isExpanded={isOpen}
264	          aria-controls={`${id}-listbox`}
265	        />
266	
267	        <TextInputGroupUtilities
268	          {...(!inputValue ? { style: { display: 'none' } } : {})}
269	        >
270	          <Button
271	            variant={ButtonVariant.plain}
272	            onClick={onClearButtonClick}
273	            aria-label={t('Clear selected value')}
274	            icon={<TimesIcon aria-hidden />}
275	          />
276	        </TextInputGroupUtilities>
277	      </TextInputGroup>
278	    </MenuToggle>
279	  );
280	  return (
281	    <div className={className}>
282	      <Select
283	        id={id}
284	        isOpen={isOpen}
285	        selected={selected}
286	        onSelect={onOptionSelect}
287	        onOpenChange={(isOpened: boolean) => {
288	          !isOpened && closeMenu();
289	        }}
290	        toggle={toggle}
291	        shouldFocusFirstItemOnOpen={false}
292	        popperProps={{ appendTo: 'inline' }}
293	      >
294	        <SelectList id={`${id}-listbox`}>
295	          {selectOptions.map((option, index) => (
296	            <SelectOption
297	              key={option.value || option.children}
298	              isFocused={focusedItemIndex === index}
299	              className={option.className}
300	              id={createItemId(option.value)}
301	              {...option}
302	              ref={null}
303	              isSelected={option.value === selected}
304	            />
305	          ))}
306	        </SelectList>
307	      </Select>
308	    </div>
309	  );
310	};

